namespace sv_e9bf6e081d804f0eb6dd4f95894a1895.Client;

public sealed class UserInfo
{
    public required string Email { get; init; }
    public required string[] Roles { get; init; }
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_e9bf6e081d804f0eb6dd4f95894a1895.Client;

/// <summary>
/// Client-side AuthenticationStateProvider that reads the user identity
/// persisted by the server into PersistentComponentState, so that auth
/// state survives the Server → WebAssembly render-mode transition.
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authenticationStateTask;

    public PersistentAuthenticationStateProvider(PersistentComponentState state)
    {
        if (!state.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo) || userInfo is null)
        {
            _authenticationStateTask = _unauthenticated;
            return;
        }

        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, userInfo.Email),
            new(ClaimTypes.Email, userInfo.Email),
        };

        foreach (var role in userInfo.Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        _authenticationStateTask = Task.FromResult(
            new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity(claims, authenticationType: "Hardcoded"))));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() =>
        _authenticationStateTask;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_e9bf6e081d804f0eb6dd4f95894a1895.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that simulates a logged-in user
/// with hardcoded claims. No real identity backend is involved.
/// </summary>
public sealed class ServerAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _state = Task.FromResult(CreateState());

    private static AuthenticationState CreateState()
    {
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
        return new AuthenticationState(new ClaimsPrincipal(identity));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _state;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_e9bf6e081d804f0eb6dd4f95894a1895.Client;

namespace sv_e9bf6e081d804f0eb6dd4f95894a1895.Auth;

/// <summary>
/// Subscribes to the <see cref="AuthenticationStateProvider"/> on the server
/// and serialises the current user into <see cref="PersistentComponentState"/>
/// so the WASM client can rehydrate the identity after the runtime switch.
/// </summary>
public sealed class PersistingServerAuthenticationStateProvider : IHostEnvironmentAuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentComponentState;
    private readonly AuthenticationStateProvider _authenticationStateProvider;
    private readonly PersistingComponentStateSubscription _subscription;

    private Task<AuthenticationState>? _authenticationStateTask;

    public PersistingServerAuthenticationStateProvider(
        PersistentComponentState persistentComponentState,
        AuthenticationStateProvider authenticationStateProvider)
    {
        _persistentComponentState = persistentComponentState;
        _authenticationStateProvider = authenticationStateProvider;

        AuthenticationStateChanged(authenticationStateProvider.GetAuthenticationStateAsync());
        authenticationStateProvider.AuthenticationStateChanged += AuthenticationStateChanged;
        _subscription = _persistentComponentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public void SetAuthenticationState(Task<AuthenticationState> authenticationStateTask)
    {
        _authenticationStateTask = authenticationStateTask;
    }

    private void AuthenticationStateChanged(Task<AuthenticationState> task)
    {
        _authenticationStateTask = task;
    }

    private async Task OnPersistingAsync()
    {
        var authState = await (_authenticationStateTask ?? _authenticationStateProvider.GetAuthenticationStateAsync());
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var email = principal.FindFirst(ClaimTypes.Email)?.Value ?? principal.Identity.Name ?? string.Empty;
            var roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray();

            _persistentComponentState.PersistAsJson(nameof(UserInfo), new UserInfo
            {
                Email = email,
                Roles = roles,
            });
        }
    }

    public void Dispose()
    {
        _subscription.Dispose();
        _authenticationStateProvider.AuthenticationStateChanged -= AuthenticationStateChanged;
    }
}

