namespace sv_e9bf6e081d804f0eb6dd4f95894a1895.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that simulates a logged-in user
/// with hardcoded claims and persists the identity into PersistentComponentState
/// so it survives the Server → WebAssembly render-mode transition.
/// </summary>
public sealed class ServerAuthenticationStateProvider : AuthenticationStateProvider, IDisposable
{
    private readonly PersistingComponentStateSubscription _subscription;
    private readonly Task<AuthenticationState> _authenticationStateTask;

    public ServerAuthenticationStateProvider(PersistentComponentState persistentComponentState)
    {
        _authenticationStateTask = Task.FromResult(CreateState());
        _subscription = persistentComponentState.RegisterOnPersisting(() =>
        {
            var state = CreateState();
            var user = state.User;
            var email = user.FindFirst(ClaimTypes.Email)?.Value ?? string.Empty;
            var roles = user.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray();

            persistentComponentState.PersistAsJson(nameof(UserInfo), new UserInfo
            {
                Email = email,
                Roles = roles,
            });

            return Task.CompletedTask;
        }, RenderMode.InteractiveWebAssembly);
    }

    private static AuthenticationState CreateState()
    {
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
        return new AuthenticationState(new ClaimsPrincipal(identity));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authenticationStateTask;

    public void Dispose() => _subscription.Dispose();
}

